-- V10 流程最佳化
alter table public.deliveries add column if not exists order_number text, add column if not exists work_order_sent boolean not null default false;
update public.deliveries set order_number=coalesce(nullif(order_number,''),nullif(sales_name_snapshot,'')) where order_number is null or order_number='';
create index if not exists deliveries_order_number_idx on public.deliveries(order_number);
create table if not exists public.delivery_reconciliations(id uuid primary key default gen_random_uuid(),delivery_id uuid not null unique references public.deliveries(id) on delete cascade,original_amount numeric(12,2) not null default 0 check(original_amount>=0),adjusted_amount numeric(12,2) not null default 0 check(adjusted_amount>=0),reconciled boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
drop trigger if exists trg_delivery_reconciliations_updated_at on public.delivery_reconciliations;create trigger trg_delivery_reconciliations_updated_at before update on public.delivery_reconciliations for each row execute function public.set_updated_at();alter table public.delivery_reconciliations enable row level security;
drop view if exists public.delivery_overview;
create view public.delivery_overview as select d.id,d.delivery_date,d.delivery_order,d.requested_period,d.constraint_type,d.earliest_time,d.latest_time,d.estimated_arrival,d.estimated_departure,d.customer_name_snapshot as customer_name,d.customer_phone_snapshot as customer_phone,d.delivery_address_snapshot as delivery_address,d.sales_name_snapshot as sales_name,d.order_number,d.work_order_sent,d.service_minutes,d.travel_minutes_from_previous,d.travel_distance_km,d.status,d.notes,d.cancelled_reason,d.created_at,d.updated_at,coalesce(item_data.items,'[]'::jsonb) as items,coalesce(task_data.tasks,'[]'::jsonb) as tasks from public.deliveries d left join lateral(select jsonb_agg(jsonb_build_object('item_id',di.id,'product_id',p.id,'product_name',coalesce(nullif(di.custom_product_name,''),p.name),'custom_product_name',di.custom_product_name,'quantity',di.quantity,'pickup_location_id',pl.id,'pickup_location_name',pl.name,'pickup_location_address',pl.address,'custom_pickup_address',di.custom_pickup_address,'item_notes',di.item_notes,'picked',di.picked) order by p.sort_order,coalesce(di.custom_product_name,p.name)) as items from public.delivery_items di join public.products p on p.id=di.product_id join public.pickup_locations pl on pl.id=di.pickup_location_id where di.delivery_id=d.id)item_data on true left join lateral(select jsonb_agg(jsonb_build_object('task_id',dt.id,'task_order',dt.task_order,'task_type',dt.task_type,'task_label',dt.task_label,'destination_address',dt.destination_address,'service_minutes',dt.service_minutes,'details',dt.details,'notes',dt.notes,'rental_start_date',dt.rental_start_date,'rental_return_date',dt.rental_return_date) order by dt.task_order,dt.created_at) as tasks from public.delivery_tasks dt where dt.delivery_id=d.id)task_data on true;